SELECT COUNT(*) AS QTDE_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB PB ON PB.PK = LPB.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE WHERE LOWER(PB.NATUREZA) = LOWER('resumo') AND LOWER(PB.TIPO) LIKE LOWER('%trabalho%') AND LOWER(S.SIGLA_CAMPUS) = LOWER('val') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%') AND PB.ANO = '2024' AND S.GENERO = 'MASCULINO'